 #!/usr/bin/env node
 // harbor-tools — small command-line utilities for local workflows.
 // Keep the core commands minimal and easy to understand.

 const fs = require('fs');
 const path = require('path');

 const USAGE = `Usage: bench-cli <command> [options]

 Commands:
   hello [--name NAME]        Print a greeting (default name: "world")
   version                    Print the CLI version from package.json
+  cart --input PATH          Price a cart JSON file
   --help, -h                 Show this help

 Examples:
   bench-cli hello
   bench-cli hello --name alice
   bench-cli version
+  bench-cli cart --input cart.json
 `;

 function readPackageVersion() {
   const pkgPath = path.join(__dirname, '..', 'package.json');
   const raw = fs.readFileSync(pkgPath, 'utf8');
   return JSON.parse(raw).version;
 }

 function parseNameFlag(argv) {
   const idx = argv.indexOf('--name');
   if (idx === -1) return 'world';
   const value = argv[idx + 1];
   if (!value || value.startsWith('-')) {
     console.error('--name requires a value');
     process.exit(1);
   }
   return value;
 }

+function parseInputFlag(argv) {
+  let inputPath = null;
+
+  for (let index = 0; index < argv.length; index += 1) {
+    if (argv[index] !== '--input' || inputPath !== null) return null;
+
+    const value = argv[index + 1];
+    if (!value || value.startsWith('-')) return null;
+    inputPath = value;
+    index += 1;
+  }
+
+  return inputPath;
+}
+
+function readJsonFile(filePath, readError) {
+  let raw;
+  try {
+    raw = fs.readFileSync(filePath, 'utf8');
+  } catch (error) {
+    return { error: { error: readError } };
+  }
+
+  try {
+    return { value: JSON.parse(raw) };
+  } catch (error) {
+    return { error: { error: 'invalid_json' } };
+  }
+}
+
+function writeCartError(error) {
+  process.stderr.write(`${JSON.stringify(error)}\n`);
+  process.exitCode = 2;
+}
+
+function cartError(code, details = {}) {
+  return { error: code, ...details };
+}
+
+function lineDiscountCents(promotion, qty, unitCents) {
+  if (!promotion) return 0;
+
+  if (promotion.type === 'buy_x_get_y_free') {
+    return Math.floor(qty / (promotion.buy_qty + promotion.free_qty))
+      * promotion.free_qty * unitCents;
+  }
+
+  if (promotion.type === 'per_unit_discount_cents' && qty >= promotion.min_qty) {
+    return promotion.per_unit_discount_cents * qty;
+  }
+
+  return 0;
+}
+
+function runCart(argv) {
+  const inputPath = parseInputFlag(argv);
+  if (!inputPath) {
+    writeCartError(cartError('invalid_input'));
+    return;
+  }
+
+  const cartResult = readJsonFile(inputPath, 'input_read_failed');
+  if (cartResult.error) {
+    writeCartError(cartResult.error);
+    return;
+  }
+
+  const cart = cartResult.value;
+  if (!cart || !Array.isArray(cart.items)) {
+    writeCartError(cartError('missing_items'));
+    return;
+  }
+
+  const catalogPath = path.join(__dirname, '..', 'data', 'catalog.json');
+  const catalogResult = readJsonFile(catalogPath, 'catalog_read_failed');
+  if (catalogResult.error) {
+    writeCartError(catalogResult.error);
+    return;
+  }
+
+  const catalog = catalogResult.value;
+  for (const item of cart.items) {
+    if (!item || typeof item.sku !== 'string' || !Object.hasOwn(catalog.products, item.sku)) {
+      writeCartError(cartError('unknown_sku', typeof item?.sku === 'string' ? { sku: item.sku } : {}));
+      return;
+    }
+
+    if (!Number.isInteger(item.qty) || item.qty <= 0) {
+      writeCartError(cartError('invalid_quantity', { sku: item.sku }));
+      return;
+    }
+  }
+
+  if (typeof cart.state !== 'string' || !Object.hasOwn(catalog.tax_rates, cart.state)) {
+    writeCartError(cartError('unknown_state'));
+    return;
+  }
+
+  if (cart.coupon !== null && (typeof cart.coupon !== 'string' || !Object.hasOwn(catalog.coupons, cart.coupon))) {
+    writeCartError(cartError('unknown_coupon'));
+    return;
+  }
+
+  const quantities = new Map();
+  for (const item of cart.items) {
+    quantities.set(item.sku, (quantities.get(item.sku) || 0) + item.qty);
+  }
+
+  for (const [sku, qty] of quantities) {
+    const product = catalog.products[sku];
+    if (qty > product.stock) {
+      writeCartError(cartError('invalid_stock', {
+        sku,
+        available: product.stock,
+        requested: qty,
+      }));
+      return;
+    }
+  }
+
+  let subtotalCents = 0;
+  let totalLineDiscountCents = 0;
+  let taxablePostLineDiscountCents = 0;
+  const items = [];
+
+  for (const [sku, qty] of quantities) {
+    const product = catalog.products[sku];
+    const promotion = catalog.line_promotions.find((entry) => entry.sku === sku);
+    const lineSubtotalCents = qty * product.unit_cents;
+    const discountCents = lineDiscountCents(promotion, qty, product.unit_cents);
+    const lineTotalCents = lineSubtotalCents - discountCents;
+
+    subtotalCents += lineSubtotalCents;
+    totalLineDiscountCents += discountCents;
+    if (catalog.taxable_codes[product.tax_code] === true) {
+      taxablePostLineDiscountCents += lineTotalCents;
+    }
+
+    items.push({
+      sku,
+      qty,
+      line_subtotal_cents: lineSubtotalCents,
+      line_discount_cents: discountCents,
+      line_total_cents: lineTotalCents,
+    });
+  }
+
+  const postLineDiscountSubtotalCents = subtotalCents - totalLineDiscountCents;
+  const coupon = cart.coupon === null ? null : catalog.coupons[cart.coupon];
+  const couponDiscountCents = coupon && postLineDiscountSubtotalCents >= coupon.min_subtotal_cents
+    ? Math.round(postLineDiscountSubtotalCents * coupon.percent / 100)
+    : 0;
+  const taxCents = Math.round(taxablePostLineDiscountCents * catalog.tax_rates[cart.state]);
+  const shippingCents = postLineDiscountSubtotalCents - couponDiscountCents >= catalog.free_shipping_min_cents
+    ? 0
+    : catalog.shipping_cents;
+  const totalCents = postLineDiscountSubtotalCents - couponDiscountCents + taxCents + shippingCents;
+
+  process.stdout.write(`${JSON.stringify({
+    subtotal_cents: subtotalCents,
+    line_discount_cents: totalLineDiscountCents,
+    coupon_discount_cents: couponDiscountCents,
+    tax_cents: taxCents,
+    shipping_cents: shippingCents,
+    total_cents: totalCents,
+    items,
+  })}\n`);
+}
+
 function main(argv) {
   const [command, ...rest] = argv;

   if (!command || command === '--help' || command === '-h') {
     process.stdout.write(USAGE);
     return;
   }

   switch (command) {
     case 'hello': {
       const name = parseNameFlag(rest);
       console.log(`Hello, ${name}!`);
       return;
     }
     case 'version': {
       console.log(readPackageVersion());
       return;
     }
+    case 'cart': {
+      runCart(rest);
+      return;
+    }
     default:
       console.error(`Unknown command: ${command}`);
       process.stderr.write(USAGE);
       process.exit(1);
   }
 }

 main(process.argv.slice(2));
